import { Button } from '@material-ui/core'
import React from 'react'
import styled from 'styled-components'
import ShoppingBasketIcon from '@material-ui/icons/ShoppingBasket';
import video from '../../video/video.mkv'
import illustration from '../../images/illustration.svg'
import Bubbles from '../../components/Bubbles';
import AboutSection from './AboutSection';
import ClientReviewsSection from './ClientReviewsSection';
import {motion} from 'framer-motion'
import Loading from '../../components/Loading'
import { useHistory } from 'react-router-dom';
import FormReviewSection from './FormReviewSection';

export default function Homepage() {
    const history = useHistory()


    const container = {
        hidden: { opacity: 0 },
        show: {
          opacity: 1,
          transition: {
            staggerChildren: 0.2,
            staggerDirection: -1,
            delayChildren: 1.3,
          }
        }
    }
    
    const item = {
        hidden: { opacity: 0, x: -100 },
        show: { opacity: 1, x: 0 }
    }

    return (
        <>
            <Loading />

            <Container >
                <Bubbles />

                <WelcomeSection>
                    <Left as={motion.article} variants={container} initial="hidden" animate="show" >
                        <H2 as={motion.h2} variants={item}>Site-uri, pagini web, bloguri pentru desktop și mobil</H2>
                        <H1 as={motion.h1} variants={item}>Site-ul <b>tău</b> ● reclama mea</H1>
                        <P as={motion.p} variants={item}>Programator <b>Front-End</b>, mă ocup cu schițarea și construirea de website-uri, site-uri e-commerce pentru vânzări online cu bază de date și autentificare Google pentru clienți mici și foarte mici. Încă la început de drum în acest domeniu pun suflet și pasiune în fiecare proiect.</P>
                        <Button 
                            component={motion.button} 
                            variants={item} size="small" 
                            endIcon={<ShoppingBasketIcon/>}
                            onClick={() => history.push("/cumpara")}
                        >
                            cumpără
                        </Button>
                    </Left>

                    <Right>
                        <Video 
                            as={motion.video} 
                            initial={{opacity: 0, y: 100}} 
                            animate={{opacity: 1, y: 0}} 
                            transition={{delay: 1.3, duration: 1}} 
                            src={video} type="video/mkv" 
                            controls 
                            autoPlay 
                            muted 
                            loop
                        >
                        </Video>
                        <Illustration 
                            as={motion.img} 
                            initial={{opacity: 0}} 
                            animate={{opacity: 1}} 
                            transition={{delay: 1.3, duration: 1}} 
                            src={illustration} 
                            alt="illustration" 
                        />
                    </Right>
                </WelcomeSection>

                <AboutSection/>

                <ClientReviewsSection/>

                <FormReviewSection/>
            </Container>
        </>
    )
}


const Container = styled.main`
    padding: 0 5vw;
    position: relative;
    overflow: hidden;
    `
const WelcomeSection = styled.div`
    min-height: calc(100vh - 100px);
    position: relative;
    z-index: 1;
    display: flex;
    margin: 0 auto;
    max-width: 1500px;
    gap: 10vw; 
    pointer-events: none;
    @media screen and (max-width: 1030px) {
        flex-direction: column;
    }
`
const Left = styled.article`
    flex: 1;
    margin: 50px 0 0;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-start;
    >button {
        border-radius: 10px;
        background: linear-gradient(125deg, var(--crd), var(--crl));
        color: white;
        font-family: var(--fsss);
        margin-top: 20px;
        padding: 10px 20px;
        pointer-events: all;
        &:hover {
            background: linear-gradient(125deg, var(--crl), var(--crl));
            animation: bounce 2s both;
            @keyframes bounce { 
                0%, 20%, 50%, 80%, 100% {
                    transform: translateY(0);
                } 
                40% {
                    transform: translateY(-5px);
                } 
                60% {
                    transform: translateY(-2px);
                } 
            }
        }
    }
    @media screen and (max-width: 900px) {
        text-align: center;
        align-items: center;
    }
`
const H2 = styled.h2`
    font-size: var(--mf);
    font-family: var(--fsss);
    font-weight: 200;
    color: grey;
    line-height: 1;
`
const H1 = styled.h1`
    font-size: var(--bf);
    font-family: var(--fsss);
    color: #2e2e2e;
    font-weight: 500;
    line-height: 1;
    margin-top: var(--sf);
    margin-bottom: var(--bf);
    >b {
        color: var(--cbd);
    }
`
const P = styled.p`
    font-size: var(--sf);
    line-height: 1.6;
    >b {
        color: var(--cbl);
    }
`
const Right = styled.article`
    flex: 1;
    display: grid;
    place-content: center;
    position: relative;
`
const Video = styled.video`
    object-fit: contain;
    width: calc(100% - 20px);
    box-shadow: 0 19px 38px rgba(0,0,0,0.30), 0 15px 32px rgba(0,0,0,0.22);
    pointer-events: all;
    border: 10px solid #272727;
    border-radius: 10px;
    @media screen and (max-width: 1000px) {
        max-height: 30vh;
    }
`
const Illustration = styled.img`
    position: absolute;
    bottom: 50%;
    left: 50%;
    object-fit: contain;
    transform: translate(-50%, 50%);
    width: 120%;
    pointer-events: none;
    @media screen and (max-width: 1000px) {
        display: none;
    }
`