import React from 'react'
import { useRef } from 'react'
import frizerie from '../../images/frizerie-devices.png'
import portfolio from '../../images/portfolio-devices.png'
import cutite from '../../images/cutite-devices.png'
import styled from 'styled-components'
import { useEffect } from 'react'
import LinkIcon from '@material-ui/icons/Link';
import ChevronRightSharpIcon from '@material-ui/icons/ChevronRightSharp';

export default function AboutSection() {
    const img1 = useRef()
    const img2 = useRef()
    const img3 = useRef()
    const text1 = useRef()
    const text2 = useRef()
    const text3 = useRef()
   
    
    useEffect(() => {
        function handleScroll() {
            if (img1.current.getBoundingClientRect().y < window.innerHeight + 200) {
                img1.current.style.opacity = 1
                img1.current.style.transform = 'translateY(0)'
            }
            if (img2.current.getBoundingClientRect().y < window.innerHeight + 200) {
                img2.current.style.opacity = 1
                img2.current.style.transform = 'translateY(0)'
            }
            if (img3.current.getBoundingClientRect().y < window.innerHeight + 200) {
                img3.current.style.opacity = 1
                img3.current.style.transform = 'translateY(0)'
            }
            if (text1.current.getBoundingClientRect().y < window.innerHeight / 1.2) {
                text1.current.style.clipPath = 'polygon(0 0, 100% 0, 100% 100%, 0 100%)'
            }
            if (text2.current.getBoundingClientRect().y < window.innerHeight / 1.2) {
                text2.current.style.clipPath = 'polygon(0 0, 100% 0, 100% 100%, 0 100%)'
            }
            if (text3.current.getBoundingClientRect().y < window.innerHeight / 1.2) {
                text3.current.style.clipPath = 'polygon(0 0, 100% 0, 100% 100%, 0 100%)'
            }
        }

        window.addEventListener('scroll', handleScroll)
    
        return () => window.removeEventListener('scroll', handleScroll)

    }, [])



    return (
        <Container >
            <Wrapper>
                <Img ref={img1} src={frizerie} alt="project"/>
                <Text ref={text1}><MyLink href="https://codmitu.github.io/frizerie-website/" target="_blank"><LinkIcon/>Website</MyLink>
                    <Ul initial="hidden" animate="show">
                        <Li><ChevronRightSharpIcon/> Website de prezentare</Li>
                        <Li><ChevronRightSharpIcon/> Pagini: 2 - 10</Li>
                        <Li><ChevronRightSharpIcon/> Design responsive</Li>
                        <Li><ChevronRightSharpIcon/> Formular de contact pe e-mail</Li>
                        <Li><ChevronRightSharpIcon/> Hosting Gratuit</Li>
                        <Li><ChevronRightSharpIcon/> Optimizare SEO</Li>
                    </Ul>
                </Text>
            </Wrapper>
            <Wrapper>
                <Text ref={text2}><MyLink href="https://codmitu.github.io/portfolio-demo/" target="_blank"><LinkIcon/>Portofoliu</MyLink>
                    <Ul>
                        <Li><ChevronRightSharpIcon/> Pagină de destinație</Li>
                        <Li><ChevronRightSharpIcon/> Pagini: 1</Li>
                        <Li><ChevronRightSharpIcon/> Design responsive</Li>
                        <Li><ChevronRightSharpIcon/> Formular de contact pe e-mail</Li>
                        <Li><ChevronRightSharpIcon/> Hosting Gratuit</Li>
                        <Li><ChevronRightSharpIcon/> Optimizare SEO</Li>
                    </Ul>
                </Text>
                <Img ref={img2} src={portfolio} alt="project"/>
            </Wrapper>
            <Wrapper>
                <Img ref={img3} src={cutite} alt="project"/>
                <Text ref={text3}><MyLink href="https://codmitu.github.io/cutite-demo/" target="_blank"><LinkIcon/>Webshop</MyLink>
                    <Ul>
                        <Li><ChevronRightSharpIcon/> Magazin online sau Blog</Li>
                        <Li><ChevronRightSharpIcon/> Pagini: nelimitate</Li>
                        <Li><ChevronRightSharpIcon/> Design responsive</Li>
                        <Li><ChevronRightSharpIcon/> Formular de contact</Li>
                        <Li><ChevronRightSharpIcon/> Review-uri clienți</Li>
                        <Li><ChevronRightSharpIcon/> Autentificare Google client/admin</Li>
                        <Li><ChevronRightSharpIcon/> Adăugare/ștergere produse</Li>
                        <Li><ChevronRightSharpIcon/> Încărcare imagini produse</Li>
                        <Li><ChevronRightSharpIcon/> Produse unice nelimitate</Li>
                        <Li><ChevronRightSharpIcon/> Hosting Gratuit</Li>
                        <Li><ChevronRightSharpIcon/> Optimizare SEO</Li>
                    </Ul>
                </Text>
            </Wrapper>
        </Container>
    )
}



const Container = styled.section`
    display: flex;
    flex-direction: column;
    pointer-events: none;
    margin-bottom: 200px;
`
const Wrapper = styled.div`
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10vw;
    margin: 10vh 0;
    @media screen and (max-width: 1030px) {
        flex-direction: column;
        justify-content: space-evenly;
        &:nth-child(2) {
            flex-direction: column-reverse;
        }
    }
` 
const Img = styled.img`
    max-width: 50%;
    max-height: 50vh;
    text-align: center;
    height: fit-content;
    transition: all 1s ease-in;
    opacity: 0.1;
    transform: translateY(200px);
    @media screen and (max-width: 1030px) {
        max-width: 90%;
        max-height: 50vh;
    }
`
const Text = styled.div`
    transition: all 1s linear .5s;
    font-family: var(--fsss);
    clip-path: polygon(0 0, 100% 0, 100% 0, 0 0);
`
const MyLink = styled.a`
    pointer-events: all;
    font-size: var(--mf);
    cursor: pointer;
    text-decoration: none;
    color: var(--cbd);
    >svg {
        color: var(--cbl);
    }
    &:hover {
        text-decoration: underline;
    }
    &:visited {
        >svg {
            color: var(--crl);
        }
    }
`
const Ul = styled.ul`
    font-size: var(--sf);
    margin-left: 50px;
`
const Li = styled.li`
    list-style: none;
    display: flex;
    align-items: center;
    margin-top: 10px;
    >svg {
        color: var(--cgd);
    }
`